import math

def is_special(num: int) -> bool:
    s = str(num)
    if s != s[::-1]:
        return False
    count = {}
    for c in s:
        d = int(c)
        count[d] = count.get(d, 0) + 1
    for d in count:
        if count[d] != d:
            return False
    return True

def solve(n: int) -> int:
    current = n + 1
    while True:
        if is_special(current):
            return current
        current += 1
